<style>
    /* --- 全局变量 --- */
    :root {
        --font-hand: 'ZCOOL KuaiLe', 'Kalam', cursive;
        --font-art: 'Ma Shan Zheng', cursive; 
        --font-serif: 'Noto Serif SC', serif;

        /* 彩虹线稿色板 */
        --sketch-red: #ff6b6b;
        --sketch-orange: #feca57;
        --sketch-yellow: #ff9f43;
        --sketch-green: #1dd1a1;
        --sketch-blue: #54a0ff;
        --sketch-purple: #5f27cd;

        --text-pencil: #4a4a4a; /* 铅笔灰 */
    }

    body { 
        display: flex; justify-content: center; 
        align-items: flex-start; /* 改为顶部对齐，去除垂直居中导致的留白 */
        margin: 0; padding: 10px; /* 减小内边距 */
        box-sizing: border-box; 
        font-family: var(--font-serif);
        min-height: auto; /* 去除强制全屏高度，让它自适应内容 */
        overflow-x: hidden;
    }

    .reverie-container {
        width: 100%; max-width: 500px;
        margin: 0 auto; /* 去掉上下margin，紧贴顶部 */
        display: none; 
        position: relative;
    }
    .reverie-container.active { display: block; }

    /* =================================================================== */
    /* --- 彩虹线稿卡片核心样式 --- */
    /* =================================================================== */

    .card-content-wrapper {
        background-color: rgba(255, 255, 255, 0.95); /* 提高不透明度以突出文字 */

        /* 模拟手绘彩虹杂边 */
        box-shadow: 
            0 0 0 4px #fff, 
            3px 3px 0 var(--sketch-red),
            -3px -2px 0 var(--sketch-blue),
            2px -3px 0 var(--sketch-yellow),
            -2px 4px 0 var(--sketch-green);

        border-radius: 255px 15px 225px 15px / 15px 225px 15px 255px;
        padding: 40px 30px;
        position: relative;
        overflow: hidden;
        font-family: var(--font-hand);
        color: var(--text-pencil);
        transition: min-height 0.4s ease;
        /* 初始高度不需要固定，由内容决定，折叠由内部容器控制 */
    }

    /* --- 背景图层 --- */
    .bg-image-layer {
        position: absolute;
        top: 0; left: 0; right: 0; bottom: 0;
        z-index: 0;
        opacity: 0.25; /* 降低不透明度，防止背景太花影响阅读 */
        background-size: cover;
        background-position: center;
        background-repeat: no-repeat;
        pointer-events: none;
        filter: contrast(1.2) brightness(1.1); /* 稍微增强线稿对比度 */
        mix-blend-mode: multiply; /* 正片叠底，让线条融入纸张 */
    }

    /* 纸张纹理 */
    .paper-texture {
        position: absolute;
        top: 0; left: 0; right: 0; bottom: 0;
        background-image: url("data:image/svg+xml,%3Csvg width='100' height='100' viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M11 18c3.866 0 7-3.134 7-7s-3.134-7-7-7-7 3.134-7 7 3.134 7 7 7zm48 25c3.866 0 7-3.134 7-7s-3.134-7-7-7-7 3.134-7 7 3.134 7 7 7z' fill='%23000000' fill-opacity='0.03' fill-rule='evenodd'/%3E%3C/svg%3E");
        pointer-events: none;
        z-index: 10;
        mix-blend-mode: multiply;
    }

    /* 装饰性背景表情 */
    .bg-expression {
        position: absolute;
        font-size: 2.5rem;
        z-index: 1;
        opacity: 0.6;
        background: linear-gradient(135deg, var(--sketch-red), var(--sketch-blue));
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        mix-blend-mode: multiply;
    }

    /* --- 内容区域 --- */
    .lineart-header {
        position: relative;
        z-index: 5;
        text-align: center;
    }

    .lineart-title {
        font-family: var(--font-art);
        font-size: 2em;
        line-height: 1.3;
        margin-bottom: 15px;
        background: linear-gradient(to right, var(--sketch-red), var(--sketch-purple), var(--sketch-blue));
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        font-weight: bold;
    }

    .lineart-meta {
        font-size: 0.9em;
        color: #888;
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 15px;
        margin-bottom: 10px;
        font-family: 'ABeeZee', sans-serif;
        font-style: italic;
    }
    .lineart-meta span::before {
        content: ''; position: absolute; left: -10px; top: 50%; transform: translateY(-50%);
        width: 4px; height: 4px; border-radius: 50%; background: var(--sketch-yellow);
    }
    .lineart-meta span { position: relative; }

    /* --- 折叠控制区 --- */
    .fold-toggle-btn {
        position: relative;
        z-index: 20;
        background: none;
        border: 2px dashed #ddd;
        border-radius: 20px;
        padding: 5px 20px;
        color: var(--sketch-blue);
        cursor: pointer;
        margin: 10px auto;
        display: block;
        font-family: var(--font-hand);
        font-size: 1rem;
        transition: all 0.3s;
        outline: none;
    }
    .fold-toggle-btn:hover {
        border-color: var(--sketch-blue);
        background: rgba(84, 160, 255, 0.1);
    }
    .fold-toggle-btn i {
        margin-right: 5px;
        transition: transform 0.3s;
    }
    .fold-toggle-btn.active i {
        transform: rotate(180deg);
    }

    /* --- 折叠内容容器 --- */
    .foldable-content {
        position: relative;
        z-index: 5;
        max-height: 0;
        overflow: hidden;
        opacity: 0;
        transition: max-height 0.6s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.4s ease;
    }
    .foldable-content.expanded {
        max-height: 1000px; /* 足够大以容纳内容 */
        opacity: 1;
        margin-top: 20px;
    }

    .lineart-body {
        font-size: 1.1em;
        line-height: 1.8;
        margin-bottom: 30px;
        padding: 0 5px;
        text-align: justify;
        color: #555;
    }
    .lineart-body strong {
        color: #333;
        background: linear-gradient(to right, rgba(255, 107, 107, 0.2), rgba(84, 160, 255, 0.2));
        border-radius: 4px;
        padding: 0 4px;
    }

    .lineart-signature {
        text-align: right;
        font-family: var(--font-art);
        font-size: 1.4em;
        color: var(--sketch-blue);
        transform: rotate(-3deg);
        margin-right: 15px;
    }

    /* 邮戳 - 默认只在展开后或底部显示，这里放外面 */
    .stamp-mark {
        position: absolute;
        bottom: 30px;
        right: 30px;
        width: 80px; height: 80px;
        border: 2px dashed #ddd;
        border-radius: 50%;
        opacity: 0.4;
        transform: rotate(-15deg);
        display: flex; flex-direction: column;
        justify-content: center; align-items: center;
        font-family: 'Monoton', cursive;
        font-size: 10px; color: #aaa;
        pointer-events: none;
        z-index: 1;
    }

    /* Excerpt 模式样式 (保留) */
    .style-excerpt .card-content-wrapper { padding: 25px 18px; font-family: 'Noto Serif SC', monospace; box-shadow: 0 5px 15px rgba(0,0,0,0.05); background: #fff; border-radius: 2px; border: 1px solid #eee; }
    .style-excerpt .receipt-brand-title { font-family: 'Monoton', cursive; font-size: 3em; text-align: center; color: #333; }
    .style-excerpt .receipt-info { display: flex; justify-content: space-between; font-size: 0.8em; border-bottom: 1px dashed #ccc; padding-bottom: 10px; margin: 15px 0;}
    .style-excerpt .item-name { font-weight: bold; text-align: center; margin-bottom: 10px;}
    .style-excerpt .item-desc { border-top: 1px dashed #eee; border-bottom: 1px dashed #eee; padding: 10px 0; margin-bottom: 10px; }
    .style-excerpt .receipt-footer { text-align: center; font-size: 0.8em; color: #aaa; margin-top: 20px; }

    #raw-data { display: none; }
</style>
</head>
<body>

<div class="reverie-container" id="reverieCard"></div>
<div id="raw-data">
$1
</div>

<script>
    document.addEventListener('DOMContentLoaded', () => {
        const cardContainer = document.getElementById('reverieCard');
        const rawData = document.getElementById('raw-data');
        if (!cardContainer || !rawData) return;

        const rawText = rawData.textContent.trim();
        const activeModeMatch = rawText.match(/模式：(\w+)\n([\s\S]*)$/);
        const mode = activeModeMatch ? activeModeMatch[1] : 'memory';
        const content = activeModeMatch ? activeModeMatch[2] : rawText;

        const cleanSymbols = (str) => str ? str.replace(/\*\*|__|~~/g, '') : '';
        const lines = content.split('\n').map(l => l.trim()).filter(Boolean).map(cleanSymbols);

        cardContainer.innerHTML = '';
        cardContainer.className = 'reverie-container';
        cardContainer.classList.add(`style-${mode}`, 'active');
        const wrapper = document.createElement('div');
        wrapper.className = 'card-content-wrapper';

        if (mode === 'excerpt') {
             // 小票模式
             wrapper.innerHTML = `
                <div class="receipt-brand-title">E C H O</div>
                <div class="receipt-info"><span>${new Date().toLocaleDateString()}</span><span>NO.001</span></div>
                <div class="item-name">记忆提取 · Receipt</div>
                <div class="item-desc">${lines[0] || ''}</div>
                <div class="item-desc" style="border:none; font-size:0.9em; color:#666;">${lines[1] || ''}</div>
                <div class="receipt-footer"><p>KEEP IT REAL</p></div>
            `;
        } else {
            // --- 彩虹线稿模式 ---

            // 1. 纸张纹理
            wrapper.innerHTML += `<div class="paper-texture"></div>`;

            // 2. 背景图片 (从用户提供的链接中随机选取)
            const bgImages = [
                'http://image.aibochinese.com/i/2025/11/26/lzhr15.jpg',
                'http://image.aibochinese.com/i/2025/11/26/lzieg1.jpg',
                'http://image.aibochinese.com/i/2025/11/26/lzjkdh.jpg'
            ];
            const randomBg = bgImages[Math.floor(Math.random() * bgImages.length)];

            const bgLayer = document.createElement('div');
            bgLayer.className = 'bg-image-layer';
            bgLayer.style.backgroundImage = `url('${randomBg}')`;
            wrapper.appendChild(bgLayer);

            // 3. 背景表情 (随机装饰)
            const colors = ['#ff6b6b', '#54a0ff', '#feca57', '#1dd1a1', '#5f27cd'];
            const faces = ['fa-music', 'fa-heart', 'fa-star', 'fa-face-smile', 'fa-cloud', 'fa-bolt'];
            for(let i=0; i<6; i++) {
                const icon = document.createElement('i');
                const faceClass = faces[Math.floor(Math.random() * faces.length)];
                icon.className = `fa-solid ${faceClass} bg-expression`;
                const color1 = colors[Math.floor(Math.random() * colors.length)];
                const color2 = colors[Math.floor(Math.random() * colors.length)];
                icon.style.background = `linear-gradient(135deg, ${color1}, ${color2})`;
                icon.style.webkitBackgroundClip = 'text';
                icon.style.webkitTextFillColor = 'transparent';
                icon.style.top = (Math.random() * 90) + '%';
                icon.style.left = (Math.random() * 90) + '%';
                icon.style.fontSize = (Math.random() * 1.5 + 1) + 'rem';
                icon.style.transform = `rotate(${Math.random() * 60 - 30}deg)`;
                wrapper.appendChild(icon);
            }

            // 4. 邮戳
            wrapper.innerHTML += `<div class="stamp-mark"><span>ECHO</span><span style="font-size:0.6em; margin-top:5px;">SKETCH</span></div>`;

            // 5. 内容填充 (支持折叠)
            const headerDiv = document.createElement('div');
            headerDiv.className = 'lineart-header';

            // 标题
            headerDiv.innerHTML += `<div class="lineart-title">${lines[0] || 'Untitled'}</div>`;

            // 时间地点 (如果有)
            if (lines.length > 1) {
                const metaParts = lines[1].split('·');
                headerDiv.innerHTML += `
                    <div class="lineart-meta">
                        <span>${metaParts[0] || ''}</span>
                        <span>${metaParts[1] || ''}</span>
                    </div>`;
            }
            wrapper.appendChild(headerDiv);

            // 切换按钮
            const toggleBtn = document.createElement('button');
            toggleBtn.className = 'fold-toggle-btn';
            toggleBtn.innerHTML = '<i class="fa-solid fa-chevron-down"></i> <span class="btn-text">Open Letter</span>';
            wrapper.appendChild(toggleBtn);

            // 可折叠区域 (正文 + 署名)
            const foldContainer = document.createElement('div');
            foldContainer.className = 'foldable-content';

            let bodyHTML = '';
            if (lines.length > 2) {
                let bodyText = lines.slice(2, lines.length - 1).join('<br>'); 
                if (lines.length === 3) bodyText = lines[2];

                const lastLine = lines[lines.length - 1];
                const isSignature = lines.length >= 4 || (lines.length === 3 && lastLine.length < 10);

                if (isSignature) {
                     if (lines.length > 3) bodyText = lines.slice(2, lines.length - 1).join('<br>');
                     bodyHTML += `<div class="lineart-body">${bodyText}</div>`;
                     bodyHTML += `<div class="lineart-signature">By ${lastLine}</div>`;
                } else {
                     bodyHTML += `<div class="lineart-body">${lines.slice(2).join('<br>')}</div>`;
                }
            } else {
                 bodyHTML += `<div class="lineart-body">...</div>`;
            }
            foldContainer.innerHTML = bodyHTML;
            wrapper.appendChild(foldContainer);

            // 绑定点击事件
            toggleBtn.addEventListener('click', () => {
                const isExpanded = foldContainer.classList.contains('expanded');
                if (isExpanded) {
                    foldContainer.classList.remove('expanded');
                    toggleBtn.classList.remove('active');
                    toggleBtn.querySelector('.btn-text').textContent = 'Open Letter';
                } else {
                    foldContainer.classList.add('expanded');
                    toggleBtn.classList.add('active');
                    toggleBtn.querySelector('.btn-text').textContent = 'Close Letter';
                }
            });
        }

        cardContainer.appendChild(wrapper);
    });
</script>
</body>
</html>
